import{_ as a,o as n,c as l,ak as o,aZ as e}from"./chunks/framework.DLt_otXO.js";const F=JSON.parse('{"title":"外连接","description":"","frontmatter":{"title":"外连接","date":"2022-09-20T23:10:35.000Z","permalink":"/pages/407f76/","categories":["java","mysql"],"tags":[null]},"headers":[],"relativePath":"java/mysql/外连接.md","filePath":"java/mysql/外连接.md","lastUpdated":1777258973000}'),p={name:"java/mysql/外连接.md"};function r(t,s,c,E,i,y){return n(),l("div",null,[...s[0]||(s[0]=[o(`<h1 id="外连接" tabindex="-1">外连接 <a class="header-anchor" href="#外连接" aria-label="Permalink to “外连接”">​</a></h1><h2 id="_1-外连接需求" tabindex="-1">1. 外连接需求 <a class="header-anchor" href="#_1-外连接需求" aria-label="Permalink to “1. 外连接需求”">​</a></h2><h4 id="_1-引出外连接" tabindex="-1">1. 引出外连接 <a class="header-anchor" href="#_1-引出外连接" aria-label="Permalink to “1. 引出外连接”">​</a></h4><p>前面我们学习的查询，是利用<code>where</code>字句对两张表或者多张表，形成的<strong>笛卡尔积</strong>进行筛选，根据<strong>关联条件</strong>，显示所有匹配的记录，匹配不上的，不显示。</p><p>比如：列出部门名称和这些部门的员工名称和工作，同时要求<strong>显示出那些没有员工的部门</strong>，如果我们使用以前的多表查询，实现如下：</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"></span>
<span class="line"><span style="color:#F97583;">SELECT</span><span style="color:#E1E4E8;"> dname , ename ,job</span></span>
<span class="line"><span style="color:#F97583;">  FROM</span><span style="color:#E1E4E8;"> emp ,dept</span></span>
<span class="line"><span style="color:#F97583;">  WHERE</span><span style="color:#79B8FF;"> emp</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">deptno</span><span style="color:#F97583;"> =</span><span style="color:#79B8FF;"> dept</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">deptno</span></span>
<span class="line"><span style="color:#F97583;">  ORDER BY</span><span style="color:#E1E4E8;"> dname</span></span></code></pre></div><img src="`+e+`"><p>我们会发现，没有员工的部门<code>40</code>没有查出来。这时我们就可以使用外连接解决这个问题。外连接分为<strong>左外连接</strong>和<strong>右外连接</strong>。</p><h4 id="_2-准备工作" tabindex="-1">2. 准备工作 <a class="header-anchor" href="#_2-准备工作" aria-label="Permalink to “2. 准备工作”">​</a></h4><p>创建学生表<code>stu</code>，并插入数据</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">CREATE</span><span style="color:#F97583;"> TABLE</span><span style="color:#B392F0;"> stu</span><span style="color:#E1E4E8;">(</span></span>
<span class="line"><span style="color:#E1E4E8;"> id </span><span style="color:#F97583;">INT</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#F97583;">  name</span><span style="color:#F97583;"> VARCHAR</span><span style="color:#E1E4E8;">(</span><span style="color:#79B8FF;">32</span><span style="color:#E1E4E8;">)</span></span>
<span class="line"><span style="color:#E1E4E8;">) </span><span style="color:#F97583;">CHARACTER</span><span style="color:#F97583;"> set</span><span style="color:#E1E4E8;"> utf8;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F97583;">INSERT INTO</span><span style="color:#E1E4E8;"> stu </span><span style="color:#F97583;">VALUES</span><span style="color:#E1E4E8;">(</span><span style="color:#79B8FF;">1</span><span style="color:#E1E4E8;">,</span><span style="color:#9ECBFF;">&#39;jack&#39;</span><span style="color:#E1E4E8;">),(</span><span style="color:#79B8FF;">2</span><span style="color:#E1E4E8;">,</span><span style="color:#9ECBFF;">&#39;tom&#39;</span><span style="color:#E1E4E8;">),(</span><span style="color:#79B8FF;">3</span><span style="color:#E1E4E8;">,</span><span style="color:#9ECBFF;">&#39;kity&#39;</span><span style="color:#E1E4E8;">),(</span><span style="color:#79B8FF;">4</span><span style="color:#E1E4E8;">,</span><span style="color:#9ECBFF;">&#39;nono&#39;</span><span style="color:#E1E4E8;">);</span></span></code></pre></div><p>创建成绩表<code>exam</code>并插入数据</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">CREATE</span><span style="color:#F97583;"> TABLE</span><span style="color:#B392F0;"> exam</span><span style="color:#E1E4E8;">(</span></span>
<span class="line"><span style="color:#E1E4E8;"> id </span><span style="color:#F97583;">INT</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">  grade </span><span style="color:#F97583;">INT</span></span>
<span class="line"><span style="color:#E1E4E8;">) </span><span style="color:#F97583;">CHARACTER</span><span style="color:#F97583;"> set</span><span style="color:#E1E4E8;"> utf8;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F97583;">INSERT INTO</span><span style="color:#E1E4E8;"> exam </span><span style="color:#F97583;">VALUES</span><span style="color:#E1E4E8;">(</span><span style="color:#79B8FF;">1</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">56</span><span style="color:#E1E4E8;">),(</span><span style="color:#79B8FF;">2</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">76</span><span style="color:#E1E4E8;">),(</span><span style="color:#79B8FF;">11</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">8</span><span style="color:#E1E4E8;">)</span></span></code></pre></div><h2 id="_2-左外连接" tabindex="-1">2. 左外连接 <a class="header-anchor" href="#_2-左外连接" aria-label="Permalink to “2. 左外连接”">​</a></h2><h3 id="_2-1-概念" tabindex="-1">2.1 概念 <a class="header-anchor" href="#_2-1-概念" aria-label="Permalink to “2.1 概念”">​</a></h3><p>如果左侧的表完全显示我们就说是左外连接（左侧的表跟右边的表没有完全匹配的记录，它也会把左边的表全部显示出来）</p><h3 id="_2-2-语法" tabindex="-1">2.2 语法 <a class="header-anchor" href="#_2-2-语法" aria-label="Permalink to “2.2 语法”">​</a></h3><p><code>SELECT ... from 表一 left join 表二 on condition</code></p><h3 id="_2-3-案例" tabindex="-1">2.3 案例 <a class="header-anchor" href="#_2-3-案例" aria-label="Permalink to “2.3 案例”">​</a></h3><p>显示所有人的成绩，如果没有成绩，也要显示改人的姓名和 id 号，成绩为空</p><h4 id="_2-2-1-使用多表查询" tabindex="-1">2.2.1 使用多表查询 <a class="header-anchor" href="#_2-2-1-使用多表查询" aria-label="Permalink to “2.2.1 使用多表查询”">​</a></h4><p>只能查出<code>jack</code>和<code>tom</code>两条结果，还要两条结果没有查出来。所以不满足需求，我们可以使用左外连接查询</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">SELECT</span><span style="color:#F97583;"> name</span><span style="color:#E1E4E8;">, </span><span style="color:#79B8FF;">stu</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">id</span><span style="color:#E1E4E8;"> ,grade</span></span>
<span class="line"><span style="color:#F97583;">  from</span><span style="color:#E1E4E8;"> stu,exam</span></span>
<span class="line"><span style="color:#F97583;">  WHERE</span><span style="color:#79B8FF;"> stu</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">id</span><span style="color:#F97583;"> =</span><span style="color:#79B8FF;"> exam</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">id</span><span style="color:#E1E4E8;">;</span></span></code></pre></div><h4 id="_2-2-2-使用左外连接查询" tabindex="-1">2.2.2 使用左外连接查询 <a class="header-anchor" href="#_2-2-2-使用左外连接查询" aria-label="Permalink to “2.2.2 使用左外连接查询”">​</a></h4><p>执行<code>sql</code>语句会查询出所有学生的成绩，没有成绩的显示为<code>null</code></p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"></span>
<span class="line"><span style="color:#F97583;">SELECT</span><span style="color:#F97583;"> name</span><span style="color:#E1E4E8;">, </span><span style="color:#79B8FF;">stu</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">id</span><span style="color:#E1E4E8;"> ,grade</span></span>
<span class="line"><span style="color:#F97583;">  from</span><span style="color:#E1E4E8;"> stu </span><span style="color:#F97583;">left JOIN</span><span style="color:#E1E4E8;"> exam</span></span>
<span class="line"><span style="color:#F97583;">  ON</span><span style="color:#79B8FF;"> stu</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">id</span><span style="color:#F97583;"> =</span><span style="color:#79B8FF;"> exam</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">id</span><span style="color:#E1E4E8;">;</span></span></code></pre></div><h2 id="_3-右外连接" tabindex="-1">3. 右外连接 <a class="header-anchor" href="#_3-右外连接" aria-label="Permalink to “3. 右外连接”">​</a></h2><h3 id="_3-1-概念" tabindex="-1">3.1 概念 <a class="header-anchor" href="#_3-1-概念" aria-label="Permalink to “3.1 概念”">​</a></h3><p>如果右侧的表完全显示我们就说是右外连接 （右侧的表跟左边的表没有完全匹配的记录，它也会把右边的表全部显示出来）</p><h3 id="_3-2-语法" tabindex="-1">3.2 语法 <a class="header-anchor" href="#_3-2-语法" aria-label="Permalink to “3.2 语法”">​</a></h3><p><code>SELECT ... from 表一 right join 表二 on condition</code></p><h3 id="_3-3-案例" tabindex="-1">3.3 案例 <a class="header-anchor" href="#_3-3-案例" aria-label="Permalink to “3.3 案例”">​</a></h3><p>显示所有成绩，如果没有名字匹配，显示空</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">SELECT</span><span style="color:#F97583;"> name</span><span style="color:#E1E4E8;">, </span><span style="color:#79B8FF;">stu</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">id</span><span style="color:#E1E4E8;"> ,grade</span></span>
<span class="line"><span style="color:#F97583;">  from</span><span style="color:#E1E4E8;"> stu </span><span style="color:#F97583;">RIGHT JOIN</span><span style="color:#E1E4E8;"> exam</span></span>
<span class="line"><span style="color:#F97583;">  ON</span><span style="color:#79B8FF;"> stu</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">id</span><span style="color:#F97583;"> =</span><span style="color:#79B8FF;"> exam</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">id</span><span style="color:#E1E4E8;">;</span></span></code></pre></div>`,34)])])}const h=a(p,[["render",r]]);export{F as __pageData,h as default};
